---
local LMatchThreeGameBaseCtrl = LXImport(".LMatchThreeGameBaseCtrl")

---@class LMatchThreeGameTouchCtrl:LMatchThreeGameBaseCtrl
local LMatchThreeGameTouchCtrl = LxClass("LMatchThreeGameTouchCtrl", LMatchThreeGameBaseCtrl)
-----------------------------------------------------------------

local Tweening = DG.Tweening
local Ease = Tweening.Ease
local YXTouchManager = CS.YXTouchManager
local math = math

-----------------------------------------------------------------
function LMatchThreeGameTouchCtrl:LMatchThreeGameTouchCtrl()
    -- 触摸的下标列表
    self._touchIndexList = {}
    self._touchIndexMap = {}

    self._clearNeedCount = gModelMatchThreeGame:GetClearNodeNeedNum()

        -- 相机
    self._camera = gLGameScene:GetCurrentSceneCamera()
end

-- 销毁
function LMatchThreeGameTouchCtrl:OnDestroy()
    self:RemoveTouchEvent()
    if self._moveSeq then
        self._moveSeq:Kill(false)
        self._moveSeq = nil
    end
end

-- 初始化
function LMatchThreeGameTouchCtrl:Init()
    self:InitTouchEvent()
end

-- 获取保存ctrl
function LMatchThreeGameTouchCtrl:InitGetCtrl()
    if not self._posCtrl then
        self._posCtrl = self:GetCtrl("Pos")
    end
    if not self._objCtrl then
        self._objCtrl = self:GetCtrl("Objs")
    end
    if not self._lineCtrl then
        self._lineCtrl = self:GetCtrl("Line")
    end

    if not self._swordCtrl then
        self._swordCtrl = self:GetCtrl("Sword")
    end
end

-- 清理触摸
function LMatchThreeGameTouchCtrl:RemoveTouchEvent()
    gLGameTouch:TouchUnRegister(LGameTouch.TOUCH_WONDER)
end

-- 触摸
function LMatchThreeGameTouchCtrl:InitTouchEvent()
    local LGameTouch = LGameTouch
    local op = LGameTouch.TOUCH_WONDER

    gLGameTouch:TouchRegister(op, LGameTouch.TOUCH_EVT_START, function(screenPos)
        if self:GetMgr():IsLock() then
            return
        end
        
        if self:IsOverUI(screenPos) then
            self:CancelUseItem()
            return
        end

        self:InitGetCtrl()

        self._lastPos = nil
        self._touchIndexList = {}
        self._touchIndexMap = {}
        local index = self._posCtrl:GetIndexByPos(screenPos)
        if not index then
            self:CancelUseItem()
            return
        end

        local obj = self._objCtrl:GetObj(index)

        if not obj then
            self:CancelUseItem()
            return
        end
        if self._mgr:IsReadyUseItem() then
            self._mgr:UseItemToIndex(index)
            return
        end

        if not obj:IsNormal() then
            return
        end

        self._lastPos = screenPos
        self:SaveIndex(index)

        self._swordCtrl:Show(self._touchIndexList[1], #self._touchIndexList)
    end)
    gLGameTouch:TouchRegister(op, LGameTouch.TOUCH_EVT_MOVE, function(screenPos)
        if not self._lastPos then
            return
        end
        if not (math.abs(self._lastPos.x - screenPos.x) > 0.02 or math.abs(self._lastPos.y - screenPos.y) > 0.02) then
            return
        end
        self:OnDrag(screenPos)
    end)
    gLGameTouch:TouchRegister(op, LGameTouch.TOUCH_EVT_END, function(screenPos)
        if not self._lastPos then
            return
        end

        self._lastPos = nil
        self:TouchEnd()
    end)
    gLGameTouch:TouchRegister(op, LGameTouch.TOUCH_EVT_CANCEL, function(screenPos)
        if not self._lastPos then
            return
        end
        self._lastPos = nil
        self:TouchEnd()
    end)
end

-- true:表示点中UI
function LMatchThreeGameTouchCtrl:IsOverUI(screenPos)
    local touchObject = YXTouchManager.EventSystemRaycastGameObject(screenPos)
    if touchObject and gLGameUI:IsUILayer(touchObject.layer) then
        return true
    end
end

-- 取消触摸
function LMatchThreeGameTouchCtrl:CancelTouch()
    self._lastPos = nil
    self._touchIndexList = {}
    self:GetMgr():TouchEnd(self._touchIndexList)
end

-- 拖拽
function LMatchThreeGameTouchCtrl:OnDrag(mousePos)
    local curNum = #self._touchIndexList
    local checkIndexList = self._posCtrl:GetAroundIndex(self._touchIndexList[curNum])

    local preIndex = nil
    if curNum >= 2 then
        preIndex = self._touchIndexList[curNum - 1]
    end

    local obj = self._objCtrl:GetObj(self._touchIndexList[1])
    local curType = obj:GetType()

    local newIndex = nil
    for _, index in ipairs(checkIndexList) do
        if not self._touchIndexMap[index] or (preIndex and preIndex == index) then
            local obj2 = self._objCtrl:GetObj(index)
            if obj2 and obj2:GetType() == curType and self._posCtrl:IsInRange(index, mousePos) then
                newIndex = index
                break
            end
        end
    end

    if not newIndex then
        self:SetLine(self._touchIndexList, mousePos)
        return
    end

    if preIndex == newIndex then
        -- 回退
        self:RemoveLastIndex()
    else
        -- 新增
        self:SaveIndex(newIndex)

        gLGameAudio:PlaySoundByRefId(361)
    end
    -- LNativeHelper.Vibrate()
    
    self._objCtrl:ChangeObjState(self._touchIndexList)
end

-- 触摸结束
function LMatchThreeGameTouchCtrl:TouchEnd()

    self:GetMgr():TouchEnd(self._touchIndexList)
end

-- 保存触摸的下标
function LMatchThreeGameTouchCtrl:SaveIndex(index)
    table.insert(self._touchIndexList, index)
    self._touchIndexMap[index] = true

    self:SetLine(self._touchIndexList)
end

-- 移除触摸的下标
function LMatchThreeGameTouchCtrl:RemoveLastIndex()
    local index = self._touchIndexList[#self._touchIndexList]
    for i, v in ipairs(self._touchIndexList) do
        if v == index then
            table.remove(self._touchIndexList, i)
            self._touchIndexMap[index] = nil
            break
        end
    end
    self:SetLine(self._touchIndexList)
end

-- 显示线
function LMatchThreeGameTouchCtrl:SetLine(indexList, mousePos)
    local posList = {}
    for _, index in ipairs(indexList) do
        local pos = self._posCtrl:GetPosByIndex(index)
        table.insert(posList, pos)
    end

    if mousePos then
        local worldPos = self._camera:ScreenToWorldPoint(mousePos)
        
        table.insert(posList, worldPos)
    end

    self._lineCtrl:SetLine(posList)
end

-- 取消使用道具
function LMatchThreeGameTouchCtrl:CancelUseItem()
    if self._mgr:IsReadyUseItem() then
        self._mgr:SetReadyUseItem(nil)
        FireEvent(EventNames.MATCH_THREE_GAME_CANCEL_USE_ITEM)
    end
end


return LMatchThreeGameTouchCtrl
